-- ============================================================================
-- 0. INREACH — COMUNICADORES VIA SATÉLITE
-- ============================================================================
insert into content_library (brand_id, category, slug, title, summary, payload, order_index, is_published)
values (
  (select id from brands where slug = 'garmin'),
  'deep_dive',
  'inreach-comunicadores-satelite',
  'inReach: comunicadores via satélite',
  'Como funciona a linha inReach, as diferenças entre Mini 2, Mini 3 e Mini 3 Plus, os planos de assinatura e como conduzir a venda.',
  jsonb_build_object('blocks', jsonb_build_array(jsonb_build_object('type', 'texto_rico', 'html', '{"html": "<h3>O que resolve</h3><p>O inReach usa a rede de satélites Iridium para enviar mensagens e acionar SOS de qualquer lugar do planeta, mesmo sem cobertura de celular. É o produto certo para quem sai da área urbana: trilhas longas, montanhismo, acampamento remoto, pesca em rios e reservatórios isolados, ou trabalho de campo em agronomia, pesquisa e guiamento.</p><h3>Mini 2 vs Mini 3 vs Mini 3 Plus</h3><p>O <strong>Mini 2</strong> é o modelo anterior. Ele já cobre o essencial: SOS interativo 24 horas em qualquer lugar do mundo, mensagens bidirecionais via satélite, rastreamento compartilhável e GPS multissistema. As limitações ficam por conta da tela monocromática sem touch, ausência de sirene integrada, bateria menor (1250 mAh) e nenhum recurso de voz ou foto via satélite.</p><p>O <strong>Mini 3</strong> é o modelo atual padrão e o mais recomendado hoje. Ele mantém tudo o que o Mini 2 oferece e acrescenta tela colorida touchscreen, GPS multibanda com fix mais rápido, mapas básicos coloridos, sirene sonora integrada, bateria maior (1800 mAh) e uma interface bem mais intuitiva. A única coisa que ainda falta nele é voz e foto via satélite.</p><p>O <strong>Mini 3 Plus</strong> é a opção premium, pensada para uso profissional e expedições. Ele parte de tudo o que o Mini 3 tem e adiciona mensagens de voz de 30 segundos via satélite, envio de fotos via satélite, a rede Iridium Certus (maior banda) e uma comunicação de emergência mais rica. É a escolha natural para guias de expedição, profissionais em campo remoto e aventureiros que viajam com frequência para lugares isolados. Em uma emergência, poder mandar uma mensagem de voz pode fazer a diferença.</p><h3>Planos de assinatura</h3><p>Desde junho de 2025 os planos antigos foram substituídos por 4 planos mensais mais simples. Um detalhe importante para a venda: é possível suspender o plano por até 12 meses sem custo, o que é um ótimo argumento para clientes sazonais.</p><ul><li><strong>Enabled</strong> (~US$7,99/mês): SOS interativo mais localização básica, sem mensagens pagas inclusas. Serve como backup de emergência.</li><li><strong>Essential</strong> (~US$14,99/mês, o mais vendido): 50 mensagens, SOS e rastreamento. Ideal para quem usa em fins de semana.</li><li><strong>Standard</strong> (~US$34,99/mês): mensagens ilimitadas, rastreamento e clima premium, para o aventureiro frequente.</li><li><strong>Expedition</strong> (~US$64,99/mês): tudo ilimitado, voltado a expedições longas e uso profissional intenso.</li></ul><p>Os preços são em dólar e cobrados no cartão internacional, então vale confirmar os valores atuais em explore.garmin.com. Há também uma taxa de ativação única de aproximadamente US$34,99.</p><h3>Como conduzir a venda</h3><p>O cliente ideal é alguém que faz trilhas longas sem sinal de celular, tem família que fica preocupada quando ele viaja, pratica montanhismo ou acampamento remoto, pesca em rios e reservatórios isolados, ou trabalha em campo. Já não faz sentido oferecer o inReach para quem só anda em trilhas urbanas com cobertura de celular, quer um GPS de corrida ou ciclismo, não aceita pagar assinatura mensal, ou está atrás apenas de um smartwatch de saúde.</p><p>Uma boa forma de abrir a conversa é perguntar se o cliente já esteve em algum lugar sem sinal de celular, seja em uma trilha mais longa, uma área rural ou uma pescaria em um rio distante. Se a resposta for sim, a venda já começou. O próximo passo é mostrar o problema real: sem sinal, se a pessoa se machucar ou se perder, como alguém vai encontrá-la? O inReach resolve isso porque funciona em qualquer lugar do mundo usando o satélite Iridium.</p><p>Para explicar o plano, vale usar uma comparação simples: é como um seguro de vida mensal, que pode ser suspenso quando não estiver em uso. Para quem vai a campo três ou quatro vezes por ano, esse é um dos investimentos mais importantes que existem.</p><h3>Quebra de objeções</h3><p><strong>\"Meu celular já tem GPS.\"</strong> O GPS do celular funciona por satélite, mas mensagens e SOS dependem de sinal de celular. No meio do Cerrado ou da Amazônia não existe torre por perto. O inReach usa a rede Iridium e funciona literalmente em qualquer ponto do planeta.</p><p><strong>\"É caro pagar todo mês.\"</strong> O plano pode ser suspenso nos meses em que não for usado, ficando zerado. Muita gente usa só dois ou três meses por ano e economiza o resto. E vale lembrar que um resgate de helicóptero custa dezenas de milhares de reais."}'::jsonb->>'html'))),
  0,
  true
)
on conflict (brand_id, category, slug) do nothing;

-- ============================================================================
-- 1. GPS DE MÃO — GPSMAP E ETREX
-- ============================================================================
insert into content_library (brand_id, category, slug, title, summary, payload, order_index, is_published)
values (
  (select id from brands where slug = 'garmin'),
  'deep_dive',
  'gps-de-mao-gpsmap-etrex',
  'GPS de mão: linhas GPSMAP e eTrex',
  'Diferenças entre as linhas GPSMAP e eTrex, quando indicar cada modelo e como identificar o cliente certo.',
  jsonb_build_object('blocks', jsonb_build_array(jsonb_build_object('type', 'texto_rico', 'html', '{"html": "<h3>Para que servem</h3><p>Os GPS portáteis Garmin são dispositivos dedicados para navegação em trilha, camping, caça e aventuras fora de área de cobertura. Funcionam sem celular, sem internet e com bateria de longa duração, cobrindo justamente o cenário onde um smartphone comum deixa a desejar.</p><h3>Linha GPSMAP: navegação avançada</h3><p>O <strong>GPSMAP 65</strong> tem tela de 2.6\" colorida, GPS multibanda e mapas TopoActive Brasil. Seu diferencial é o GPS multibanda combinado com múltiplos satélites, além de botões físicos que funcionam bem mesmo com luvas. É indicado para o trilheiro ou aventureiro em geral.</p><p>O <strong>GPSMAP 65s</strong> parte do 65 e adiciona barômetro e bússola de 3 eixos, com um altímetro mais preciso. É a opção para quem já pratica trekking avançado.</p><p>O <strong>GPSMAP 67</strong> tem a tela maior da linha (3.0\") e reúne altímetro, bússola, barômetro e USB-C. É o modelo mais completo da linha portátil, voltado para expedição e aventura mais exigente.</p><p>O <strong>GPSMAP 79</strong> foge um pouco do perfil de trilha: é um GPS portátil flutuante, com Multi-GNSS, mapas BlueChart G3 e resistência à água IPX7, pensado para uso náutico e pesca.</p><p>O <strong>GPSMAP 86</strong> segue a mesma linha náutica, com tela de 3.0\", Multi-GNSS, mapas BlueChart G3, além de bússola e barômetro, voltado para quem navega em embarcações.</p><p>Já o <strong>GPSMAP H1i</strong> tem tela touch de 3.5\", Multi-GNSS e mapas TopoActive combinados com mapas de caça. Seu diferencial é o rastreamento de animais e os mapas de propriedade, voltados ao caçador mais avançado.</p><h3>Linha eTrex: robustez e simplicidade</h3><p>O <strong>eTrex 22x</strong> é a entrada da linha: tela de 2.2\" colorida, GPS+GLONASS, mapas TopoActive, bússola básica via GPS e bateria em pilhas AA. Serve bem o caminhante iniciante.</p><p>O <strong>eTrex 32x</strong> parte do 22x e adiciona bússola real de 3 eixos e altímetro barométrico, para quem precisa saber a direção sem precisar se mover. É indicado para o trilheiro que já pratica trekking com mais regularidade.</p><p>O <strong>eTrex Touch</strong> é a única versão da linha com touchscreen (tela de 2.6\"), o que deixa a navegação pelos menus mais fácil. É uma boa opção para o usuário mais casual que prefere tocar em vez de usar botões.</p><p>O <strong>eTrex Solar</strong> tem tela monocromática de 2.2\", GPS Multi-GNSS com 5 constelações, carregamento solar e bateria de até 100 horas. É a escolha certa para quem passa dias sem acesso a carregador, em expedições longas.</p><h3>Como identificar o cliente e apresentar</h3><p>Vale ficar atento quando o cliente pergunta por \"GPS de mão\" ou \"GPS portátil\", menciona trilha longa, camping ou expedição, fala de caça ou pesca em local remoto, quer algo que funcione sem celular e sem internet, menciona bateria de pilha AA porque pretende trocá-la em campo, ou pergunta sobre mapas do Brasil offline.</p><p>Na apresentação, o GPSMAP 65 e o 67 são indicados para trilheiros que querem o melhor em GPS multibanda. O eTrex 22x e o 32x entram pelo custo-benefício, com bateria AA e operação simples. O eTrex Solar atende quem vai a expedições longas e não quer se preocupar com carregador. O GPSMAP 79 e o 86 são para clientes que também usam o aparelho em barco. Já o H1i é para caçadores, com destaque para o rastreamento de animais e os mapas de propriedade.</p><p>Um bom argumento sobre bateria: a pilha AA do eTrex muda tudo para quem vai a campo por vários dias, já que é possível comprar duas pilhas em um posto de gasolina no meio do sertão e seguir navegando, algo que nenhum relógio ou celular consegue fazer. Comparando as duas linhas, o GPSMAP tem tela maior, GPS multibanda e USB-C, enquanto o eTrex é mais compacto, mais barato e usa pilha AA. Para expedições longas sem acesso a carregador, o eTrex Solar ou o eTrex com pilha AA levam vantagem na praticidade."}'::jsonb->>'html'))),
  1,
  true
)
on conflict (brand_id, category, slug) do nothing;

-- ============================================================================
-- 2. LINHA NÁUTICA — SONARES E CHARTPLOTTERS
-- ============================================================================
insert into content_library (brand_id, category, slug, title, summary, payload, order_index, is_published)
values (
  (select id from brands where slug = 'garmin'),
  'deep_dive',
  'linha-nautica-sonares-chartplotters',
  'Linha náutica: sonares e chartplotters',
  'Os três degraus da linha náutica Garmin, do sonar de entrada ao chartplotter com mapas náuticos.',
  jsonb_build_object('blocks', jsonb_build_array(jsonb_build_object('type', 'texto_rico', 'html', '{"html": "<h3>Para quem é</h3><p>A linha náutica reúne sonares e chartplotters para quem leva a sério a pesca e a navegação em rios, lagos e mar.</p><h3>Os três modelos</h3><p>O <strong>Striker 4</strong> é a entrada da linha: um sonar de pesca de 3,5\" com GPS básico. É a porta de entrada para localizar peixes com tecnologia, voltado à pesca recreativa em rios e represas.</p><p>O <strong>Striker Vivid 5cv</strong> sobe um degrau, com tela de 5\" colorida e vívida, sonar ClearVü e GPS. Com o ClearVü, o pescador vê os peixes abaixo e ao lado do barco, o que faz dele uma boa opção para quem já pratica a pesca de forma mais dedicada.</p><p>No topo está o <strong>ECHOMAP UHD2 52cv</strong>, um chartplotter com sonar UHD2 de 5\" e mapas náuticos BlueChart G3. É a opção para o pescador ou navegador mais sério, que precisa de mapas detalhados além do sonar.</p><h3>Argumento de venda</h3><p>Com o sonar ClearVü do Vivid 5cv, o pescador vê os peixes embaixo do barco quase como em uma foto, em vez de apenas manchas tradicionais no sonar comum."}'::jsonb->>'html'))),
  2,
  true
)
on conflict (brand_id, category, slug) do nothing;

-- ============================================================================
-- 3. EDGE — CICLOCOMPUTADORES
-- ============================================================================
insert into content_library (brand_id, category, slug, title, summary, payload, order_index, is_published)
values (
  (select id from brands where slug = 'garmin'),
  'deep_dive',
  'edge-ciclocomputadores',
  'Edge: ciclocomputadores para guidão',
  'Funcionalidades da linha Edge (ClimbPro, Guia de Energia, Dinâmicas de Ciclismo, GroupRide, LiveTrack), o comparativo entre os modelos 540 a 1050 e como conduzir a venda.',
  jsonb_build_object('blocks', jsonb_build_array(jsonb_build_object('type', 'texto_rico', 'html', '{"html": "<h3>O que é a linha Edge</h3><p>A linha Edge é um GPS dedicado para ciclismo, pensado para estrada, MTB, gravel e cicloviagem. A tela é maior que a de qualquer relógio, permanece legível sob sol forte e traz funcionalidades específicas que não cabem no pulso. Os modelos atuais são o Edge 540, 550, 840, 850, 1040 e 1050.</p><h3>Funcionalidades</h3><h3>ClimbPro</h3><p>O ClimbPro mostra dados detalhados de cada subida da rota carregada: nome, distância até o início, comprimento total, ganho de altitude e gradiente médio e máximo. O ciclista sabe exatamente o que vai enfrentar antes de chegar à base da subida, o que ajuda a preparar o ritmo com antecedência em vez de ser surpreendido na metade do caminho. Está disponível em todos os modelos da linha: 540, 550, 840, 850, 1040 e 1050.</p><h3>Guia de Energia (Stamina)</h3><p>O Guia de Energia monitora em tempo real a reserva de energia do ciclista, com base no esforço, na potência e na distância restante da rota. Ele mostra quanto tempo ou distância o atleta ainda consegue manter o ritmo atual antes de bater na parede, e avisa quando é hora de reduzir o esforço para terminar a prova. É como o indicador de combustível de um carro, só que aplicado ao corpo do atleta: dá para saber se vai sobrar energia ou se é preciso economizar desde já para não sofrer nos últimos quilômetros. Está presente no Edge 840, 850, 1040 e 1050, mas não no 540 nem no 550, e exige uma rota carregada no dispositivo para que a estimativa apareça corretamente.</p><h3>Dinâmicas de Ciclismo</h3><p>São métricas avançadas de pedalada que exigem pedais com medidor de potência (linha Rally) ou um cassete Shimano Di2 compatível. Elas incluem a posição da plataforma de força (onde o pé aplica força no pedal), a suavidade de pedalada (quão redonda é a pedalada), o equilíbrio entre a perna esquerda e a direita, e a fase de potência (em qual ponto do giro o ciclista gera mais força). Com os pedais Rally, o Edge mostra se o ciclista está pedalando de forma eficiente ou desperdiçando energia, como se um técnico estivesse analisando a biomecânica em tempo real. Disponível no 840, 850, 1040 e 1050; não funciona nos modelos 540 e 550, nem funciona sozinho no Edge sem o pedal Rally RS/RK/XC ou o cassete Di2 compatível.</p><h3>GroupRide</h3><p>O GroupRide permite criar ou entrar em um grupo virtual, no qual todos os participantes com um Edge compatível aparecem no mapa em tempo real. Dá para ver onde cada colega do grupo está, receber alertas se alguém ficou para trás e enviar mensagens simples predefinidas, como \"aguarde\" ou \"problema mecânico\". Para grupos de pedal e treinos em equipe, isso resolve o problema clássico de perder o companheiro no meio do pelotão: todos aparecem no mapa, então dá para saber na hora se alguém furou ou se separou. Funciona via conexão de dados do celular pareado e exige que todos os participantes também tenham um Edge compatível. Disponível no 840, 850, 1040 e 1050.</p><h3>LiveTrack</h3><p>O LiveTrack compartilha a localização em tempo real do ciclista por meio de um link, que família, amigos ou o técnico podem acompanhar direto pelo navegador, sem precisar instalar nenhum aplicativo. O ciclista ativa antes de sair e o Edge transmite a posição via celular pareado, o que é útil em pedais longos e treinos solo em locais isolados. Basta enviar o link pelo WhatsApp antes de sair, e a família acompanha o percurso em tempo real, sem precisar ligar para saber se já chegou. Está disponível em toda a linha (540, 550, 840, 850, 1040 e 1050) e exige celular pareado com dados ativos durante o pedal.</p><h3>Modelos e comparativo</h3><p>Todos os modelos trazem GPS multibanda (SatIQ), ClimbPro, mapa de rota, navegação turn-by-turn e LiveTrack. A diferença está nas funcionalidades avançadas e na tela.</p><p>O <strong>Edge 540 e 550</strong> formam a família de entrada: tela de 2.6\", GPS multibanda, ClimbPro e navegação precisa, em um corpo compacto com botões físicos que funcionam bem com luvas. O 550 é o lançamento de 2025, com tela de 1000 nits e speaker integrado. Nenhum dos dois tem GroupRide, Guia de Energia ou Dinâmicas de Ciclismo. A bateria em GPS dura cerca de 26 horas no 540 e 12 horas no 550.</p><p>O <strong>Edge 840 e 850</strong> formam a família intermediária, e são a recomendação de melhor custo-benefício da linha. Trazem touchscreen combinado com botões físicos, e é aqui que aparecem o Guia de Energia, as Dinâmicas de Ciclismo e o GroupRide. O 850, também de 2025, tem tela de 1000 nits e speaker. A bateria em GPS dura cerca de 26 horas no 840 e 12 horas no 850.</p><p>O <strong>Edge 1040 e 1050</strong> formam a família premium, com a maior tela da linha (3.5\"). O 1040 tem opção de carregamento solar, o que estende a bateria para cerca de 35 horas em GPS. O 1050, de 2025, soma tela de 1000 nits, microfone, Garmin Pay e alertas de perigo, com bateria de cerca de 20 horas em GPS. É a opção para quem quer o máximo que a linha oferece.</p><p>Entre o 540 e o 550, a escolha é simples: o 540 tem botões físicos, sem speaker, e é a opção de entrada; o 550 tem tela de 1000 nits, mais legível no sol, e speaker para alertas sonoros. Os dois têm GPS multibanda, ClimbPro e LiveTrack, e nenhum dos dois tem GroupRide, Guia de Energia ou Dinâmicas de Ciclismo.</p><h3>Como conduzir a venda</h3><p>O argumento principal é direto: o celular no guidão trava no sol, esquenta, a tela apaga, e ainda falta as métricas específicas de ciclismo que o Edge oferece. Um ciclocomputador dedicado é a ferramenta certa para quem leva o pedal a sério.</p><p>Alguns sinais de que o cliente quer um Edge: ele usa o celular no suporte e reclama que esquenta ou a tela apaga, pedala em grupo e quer ver onde os amigos estão, faz subidas longas e quer planejar o esforço, já tem um medidor de potência Rally e quer extrair mais dados dele, faz pedais de mais de 5 horas e precisa de bateria longa, ou treina com técnico usando TrainingPeaks ou Zwift.</p><p>Para indicar o modelo certo: o pedaleiro iniciante fica bem servido pelo Edge 540 ou 550, com GPS preciso e simples. Quem pedala em grupo e treina com mais seriedade se beneficia do 840 ou 850, com GroupRide e Guia de Energia. Quem já usa pedais Rally e quer aproveitar as Dinâmicas de Ciclismo deve ir para o 840 ou acima. Quem faz gran fondos e centuries se beneficia do 1040, com bateria solar e tela grande. E o ciclista de elite, que quer tudo, fica com o Edge 1050.</p><p>Uma boa forma de conduzir a conversa é perguntar se o cliente pedala mais em estrada, MTB ou gravel, e se treina sozinho ou em grupo. Pedal em grupo pede o GroupRide (840 ou acima), pedal solo em subidas pede o ClimbPro (presente em todos), e quem usa medidor de potência se beneficia das Dinâmicas (840 ou acima). Vale também mostrar o ClimbPro na prática: numa Gran Fondo com três subidas pela frente, o Edge já mostra no mapa qual é a próxima, quantos quilômetros ela tem e qual é o gradiente médio, então o ciclista não é mais pego de surpresa por uma subida. Para quem pedala em grupo, vale destacar o GroupRide: quando alguém do grupo fura o pneu ou fica para trás, em vez de descobrir 10 km depois, todos aparecem no mapa em tempo real, e ainda dá para mandar uma mensagem para o grupo direto pelo Edge.</p><h3>Quebra de objeções</h3><p><strong>\"Meu celular com suporte já funciona.\"</strong> O celular no sol esquenta, trava e a tela escurece automaticamente. O Edge tem tela de até 1000 nits, feita para sol forte, não esquenta, não trava e não depende de sinal para o GPS funcionar. Além disso, o celular não tem ClimbPro, GroupRide nem Guia de Energia.</p><p><strong>\"Meu relógio Garmin já mede ciclismo.\"</strong> O relógio é ótimo para multiesporte, mas o Edge tem tela três vezes maior, navegação por mapa com visão de pássaro, ClimbPro com gráfico da subida e GroupRide. Para quem leva o ciclismo a sério, os dois acabam se complementando.</p><p><strong>\"Qual a diferença do 540 para o 840?\"</strong> O 540 tem GPS multibanda e ClimbPro, o que já é excelente para navegação precisa. O 840 soma o Guia de Energia, para saber se vai ter energia suficiente até o final, as Dinâmicas de Ciclismo para quem tem pedais de potência, e o GroupRide para pedalar em grupo. Para quem treina sério ou pedala em grupo, o 840 vale bem mais.</p><p>Um upsell natural: se o cliente já tem ou pretende comprar os pedais Rally RK 200 (SPD), vale indicar o Edge 840 ou superior, já que é essa combinação que libera todas as Dinâmicas de Ciclismo e transforma os dados de potência em informações reais sobre a pedalada."}'::jsonb->>'html'))),
  3,
  true
)
on conflict (brand_id, category, slug) do nothing;

-- ============================================================================
-- FIM DA SEED 060
-- ============================================================================
